        const __m256d ew4r = _mm256_fmsub_pd(ew2r,ew2r,_mm256_mul_pd(ew2i,ew2i));
        const __m256d ew4i = _mm256_fmadd_pd(ew2r,ew2i,_mm256_mul_pd(ew2i,ew2r));
